//! Future enhancements may include floating-point support and advanced functions.

use std::fmt;
use std::error::Error;

/// Represents calculation errors
#[derive(Debug, Clone)]
pub enum CalcError {
    DivisionByZero,
    Overflow,
}

impl fmt::Display for CalcError {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            CalcError::DivisionByZero => write!(f, "Division by zero"),
            CalcError::Overflow => write!(f, "Arithmetic overflow"),
        }
    }
}

impl Error for CalcError {}

/// A simple calculator for basic arithmetic operations
///
/// The Calculator struct provides methods for common mathematical operations.
/// All operations work with 32-bit integers and support error handling.
pub struct Calculator;

impl Calculator {
    /// Adds two numbers together
    pub fn add(a: i32, b: i32) -> i32 {
        a + b
    }

    /// Multiplies two numbers together  
    pub fn multiply(a: i32, b: i32) -> i32 {
        a * b
    }

    /// Subtracts the second number from the first
    pub fn subtract(a: i32, b: i32) -> i32 {
        a - b
    }

    /// Divides the first number by the second
    pub fn divide(a: i32, b: i32) -> Result<i32, CalcError> {
        if b == 0 {
            Err(CalcError::DivisionByZero)
        } else {
            Ok(a / b)
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_add() {
        assert_eq!(Calculator::add(2, 3), 5);
    }

    #[test]
    fn test_subtract() {
        assert_eq!(Calculator::subtract(5, 3), 2);
    }
}
